/**
 * User notification preferences model.
 *
 * Controls how and when notifications are delivered to a user across
 * multiple channels (email, SMS, webhook).
 *
 * DECISION CHANGE (Agent 9): The original email-only assumption from
 * Agent 3 is no longer valid. SMS was added in Agent 8, and this model
 * now supports per-channel preferences. The email-specific API
 * (shouldSendEmail, updateEmailPreferences, etc.) is preserved for
 * backward compatibility, but the recommended API is the channel-agnostic
 * shouldSendNotification / updateChannelPreferences.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

/**
 * Delivery frequency for a notification channel.
 * - 'immediate': send as events occur
 * - 'daily_digest': batch into a daily summary
 * - 'weekly_digest': batch into a weekly summary
 * - 'none': do not send notifications on this channel
 */
export type NotificationFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'none';

/** @deprecated Use NotificationFrequency instead. Kept for backward compatibility. */
export type EmailFrequency = NotificationFrequency;

/**
 * Per-channel notification preferences.
 * Shared structure used by all channels.
 */
export interface ChannelNotificationPreferences {
  enabled: boolean;
  frequency: NotificationFrequency;
  subscribedCategories: NotificationType[];
}

/** @deprecated Use ChannelNotificationPreferences instead. Kept for backward compatibility. */
export type EmailNotificationPreferences = ChannelNotificationPreferences;

/**
 * Full user preferences record with per-channel settings.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: ChannelNotificationPreferences;
  sms: ChannelNotificationPreferences;
  webhook: ChannelNotificationPreferences;
  updatedAt: Date;
}

/**
 * Input for updating preferences on any channel.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdateChannelPreferencesInput {
  enabled?: boolean;
  frequency?: NotificationFrequency;
  subscribedCategories?: NotificationType[];
}

/** @deprecated Use UpdateChannelPreferencesInput instead. Kept for backward compatibility. */
export type UpdateEmailPreferencesInput = UpdateChannelPreferencesInput;

/**
 * Default preferences for email — all categories enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: ChannelNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Default preferences for SMS — all categories enabled, immediate delivery.
 */
export const DEFAULT_SMS_PREFERENCES: ChannelNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Default preferences for webhook — all categories enabled, immediate delivery.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: ChannelNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'welcome',
    'account_updated',
  ],
};

/**
 * Map of channel to its default preferences.
 */
export const DEFAULT_CHANNEL_PREFERENCES: Record<string, ChannelNotificationPreferences> = {
  email: DEFAULT_EMAIL_PREFERENCES,
  sms: DEFAULT_SMS_PREFERENCES,
  webhook: DEFAULT_WEBHOOK_PREFERENCES,
};

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences with sensible defaults.
 * When a user has no saved preferences, default preferences are returned
 * (all notifications enabled, immediate delivery on all channels).
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 * The email-specific methods (updateEmailPreferences, shouldSendEmail)
 * are preserved for backward compatibility.
 *
 * Depends on:
 * - PreferencesRepository for persistence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdateChannelPreferencesInput,
  ChannelNotificationPreferences,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
  DEFAULT_CHANNEL_PREFERENCES,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. For testing only. */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

function copyChannelPrefs(prefs: ChannelNotificationPreferences): ChannelNotificationPreferences {
  return { ...prefs, subscribedCategories: [...prefs.subscribedCategories] };
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns default preferences if none are saved.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: copyChannelPrefs(DEFAULT_EMAIL_PREFERENCES),
      sms: copyChannelPrefs(DEFAULT_SMS_PREFERENCES),
      webhook: copyChannelPrefs(DEFAULT_WEBHOOK_PREFERENCES),
      updatedAt: new Date(),
    };
  }

  /**
   * Update preferences for a specific channel.
   * Creates a new preferences record if one doesn't exist.
   */
  updateChannelPreferences(
    userId: string,
    channel: 'email' | 'sms' | 'webhook',
    input: UpdateChannelPreferencesInput,
  ): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const currentChannel = existing[channel];
      const updatedChannel: ChannelNotificationPreferences = {
        ...currentChannel,
        ...(input.enabled !== undefined && { enabled: input.enabled }),
        ...(input.frequency !== undefined && { frequency: input.frequency }),
        ...(input.subscribedCategories !== undefined && { subscribedCategories: input.subscribedCategories }),
      };

      const updated = this.preferencesRepository.update(existing.id, {
        [channel]: updatedChannel,
        updatedAt: new Date(),
      } as Partial<UserPreferences>);

      this.logger.info(`Updated ${channel} preferences for user ${userId}`);
      return updated;
    }

    const defaults = DEFAULT_CHANNEL_PREFERENCES[channel];
    const newPrefs: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: copyChannelPrefs(DEFAULT_EMAIL_PREFERENCES),
      sms: copyChannelPrefs(DEFAULT_SMS_PREFERENCES),
      webhook: copyChannelPrefs(DEFAULT_WEBHOOK_PREFERENCES),
      updatedAt: new Date(),
    };

    // Apply the input to the specified channel
    newPrefs[channel] = {
      enabled: input.enabled ?? defaults.enabled,
      frequency: input.frequency ?? defaults.frequency,
      subscribedCategories: input.subscribedCategories ?? [...defaults.subscribedCategories],
    };

    this.preferencesRepository.save(newPrefs);
    this.logger.info(`Created preferences for user ${userId} (${channel})`);
    return newPrefs;
  }

  /**
   * Update email notification preferences for a user.
   * Backward-compatible wrapper around updateChannelPreferences.
   */
  updateEmailPreferences(userId: string, input: UpdateChannelPreferencesInput): UserPreferences {
    return this.updateChannelPreferences(userId, 'email', input);
  }

  /**
   * Update SMS notification preferences for a user.
   */
  updateSmsPreferences(userId: string, input: UpdateChannelPreferencesInput): UserPreferences {
    return this.updateChannelPreferences(userId, 'sms', input);
  }

  /**
   * Update webhook notification preferences for a user.
   */
  updateWebhookPreferences(userId: string, input: UpdateChannelPreferencesInput): UserPreferences {
    return this.updateChannelPreferences(userId, 'webhook', input);
  }

  /**
   * Channel-agnostic check: should a notification be sent to this user
   * on the given channel for the given notification type?
   *
   * Returns true if the channel is enabled, frequency is not 'none',
   * and the category is in the subscribed list.
   *
   * For channels without explicit preference support (e.g. in_app),
   * returns true by default (don't block unknown channels).
   */
  shouldSendNotification(
    userId: string,
    notificationType: NotificationType,
    channel: NotificationChannel,
  ): boolean {
    const prefs = this.getPreferences(userId);

    const channelPrefs = (prefs as Record<string, unknown>)[channel] as
      | ChannelNotificationPreferences
      | undefined;

    if (!channelPrefs) {
      // Unknown channel — allow by default
      return true;
    }

    if (!channelPrefs.enabled) {
      return false;
    }
    if (channelPrefs.frequency === 'none') {
      return false;
    }
    return channelPrefs.subscribedCategories.includes(notificationType);
  }

  /**
   * Check whether email notifications should be sent to a user.
   * @deprecated Use shouldSendNotification(userId, type, 'email') instead.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSendNotification(userId, notificationType, 'email');
  }
}

